-- Issue #254: correct the Ikitsuki broad representative and add three fishing ports without reassigning user data.
update public.fishing_spots
set latitude = 33.407104,
    longitude = 129.424733
where id = 'ikitsuki-area' and is_active = true;

insert into public.fishing_spots (id,name,area_name,latitude,longitude,spot_type,shore_access,coordinate_precision,target_species,recommended_methods,notes,is_active) values
('ikitsuki-fishing-port', '生月漁港', '平戸', 33.392334, 129.43306, '漁港', '不明', 'approximate', array[]::text[], array[]::text[], array['国土地理院の地名代表点を基準にした港域の概略代表点であり、入口、岸壁、堤防先端、駐車位置、実釣位置、危険箇所を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法・設備・地形・SCORE情報は直接根拠不足のため掲載していません。']::text[], true),
('tachiura-fishing-port', '館浦漁港', '平戸', 33.361458, 129.430984, '漁港', '不明', 'approximate', array[]::text[], array[]::text[], array['国土地理院の地名代表点を基準にした港域の概略代表点であり、入口、岸壁、堤防先端、駐車位置、実釣位置、危険箇所を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法・設備・地形・SCORE情報は直接根拠不足のため掲載していません。']::text[], true),
('misaki-fishing-port', '御崎漁港', '平戸', 33.431702, 129.429291, '漁港', '不明', 'approximate', array[]::text[], array[]::text[], array['国土地理院の地名代表点を基準にした港域の概略代表点であり、入口、岸壁、堤防先端、駐車位置、実釣位置、危険箇所を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法・設備・地形・SCORE情報は直接根拠不足のため掲載していません。']::text[], true)
on conflict (id) do nothing;

